import{_ as n,c as a,a as i,o as e}from"./app-CEcM0piI.js";const l={};function p(d,s){return e(),a("div",null,s[0]||(s[0]=[i(`<p>定义了四个标准流对象 重定向：将输入的源或输出的目的地改变、</p><h2 id="cin标准输入流" tabindex="-1"><a class="header-anchor" href="#cin标准输入流"><span>cin标准输入流</span></a></h2><p>用于从键盘读取数据，也可以重定向为从文件中读取数据</p><p>在Windows中在单独一行按ctrl+z和回车键就代表输出结束 IUNIX/Linux中ctrl+d代表输出结束</p><h5 id="get函数" tabindex="-1"><a class="header-anchor" href="#get函数"><span>get函数</span></a></h5><p>不会跳过空格、制表符、回车等特殊字符</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>c=cin.get();</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="cout标准输出流" tabindex="-1"><a class="header-anchor" href="#cout标准输出流"><span>cout标准输出流</span></a></h2><p>用于向屏幕输出出错信息，不能重定向</p><h2 id="endl" tabindex="-1"><a class="header-anchor" href="#endl"><span>endl</span></a></h2><p>endl和换行符并不同,它用于结束当前行的输出并刷新缓冲区</p><h3 id="流操控算子控制输出格式" tabindex="-1"><a class="header-anchor" href="#流操控算子控制输出格式"><span>流操控算子控制输出格式</span></a></h3><p>流操纵算子（格式控制符） 常用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>*dec//以十进制形式输出整数</span></span>
<span class="line"><span>hex//以十六进制形式输出整数</span></span>
<span class="line"><span>oct//以八进制形式输出整数</span></span>
<span class="line"><span>fixed//以普通小数形式输出浮点数</span></span>
<span class="line"><span>scientific//以科学计数法形式输出浮点数</span></span>
<span class="line"><span>left//左对齐，即在宽度不足时将填充字符添加到右边</span></span>
<span class="line"><span>*right//右对齐，即在宽度不足时将填充字符添加到左边</span></span>
<span class="line"><span>setbase(b)设置输出整数时的进制，b=8、10或16</span></span>
<span class="line"><span>setw(w)//指定输出宽度为w个字符，或输人字符串时读入W个字符</span></span>
<span class="line"><span>setfill(c)//在指定输出宽度的情况下，输出的宽度不足时用字符c填充(默认情况是用空格填充)</span></span>
<span class="line"><span>setprecision(n)//设置输出浮点数的精度为n。在使用非 fixed且非scientific方式输出的情况下，n即为有效数字最多的位数，如果有效数字位数超过n，则小数部分四舍五人，或自动变为科学计数法输出并保留一共n位有效数字;在使用fxed 方式和 sci-entific方式输出的情况下，n是小数点后面应保留的位数</span></span>
<span class="line"><span>setiosflags(标志)//将某个输出格式标志置为1</span></span>
<span class="line"><span>resetiosflags(标志)//将某个输出格式标志置为0</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>不常用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>boolapha//把true和false输出为字符串</span></span>
<span class="line"><span>*noboolalpha//把true和false输出为0、1</span></span>
<span class="line"><span>showbase//输出表示数值的进制的前缀</span></span>
<span class="line"><span>*noshowbase//不输出表示数值的进制的前缀</span></span>
<span class="line"><span>showpoint//总是输出小数点</span></span>
<span class="line"><span>*noshowpoint//只有当小数部分存在时才显示小数点</span></span>
<span class="line"><span>showpos//在非负数值中显示+</span></span>
<span class="line"><span>*noshowpos//在非负数值中不显示+</span></span>
<span class="line"><span>*skipws//输入时跳过空白字符</span></span>
<span class="line"><span>noskipws//输人时不跳过空白字符</span></span>
<span class="line"><span>uppercase//十六进制数中使用&#39;A~&#39;E。若输出前缀，则前缀输出“0X”，科学计数法中输出E</span></span>
<span class="line"><span>*nouppercase//十六进制数中使用&#39;a ~&#39;e。若输出前缀，则前缀输出“0x”，科学计数法中输出&#39;e&#39;</span></span>
<span class="line"><span>internal//数值的符号(正负号)在指定宽度内左对齐，数值右对齐，中间由填充字符填充</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中的“ * ”不是算子的一部分，* 表示默认使用该算子 这些算子的使用方法是用&quot;&lt;&lt;&quot;和cout连用</p><p>算子的标志:</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ios::left</span></span>
<span class="line"><span>ios::right</span></span>
<span class="line"><span>ios::internal</span></span>
<span class="line"><span>ios::showbase</span></span>
<span class="line"><span>ios::showpos</span></span>
<span class="line"><span>ios::showpoint</span></span>
<span class="line"><span>ios::uppercase</span></span>
<span class="line"><span>ios::fixed</span></span>
<span class="line"><span>ios;:scientific</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>标志的含义和同名算子一样 这些标志实际上是某比特位为1，其他比特位为0的整数 多个标志可以用“|”运算符连接，表示同时设置</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>cout&lt;&lt;setiosflags(ios::scientific|ios::showpos)&lt;&lt;12.34;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果两个相互矛盾的标志被同时设置（如fixed、scientific）那么结果可能是两个标志都不起作用</p><p>setw算子起的作用是一次性的只影响下一次输出每次需要指定输出宽度时都要使用setw setw还可以控制cin</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>string s1,s2;</span></span>
<span class="line"><span>cin&gt;&gt;setw(4)&gt;&gt;s1,setw(3)&gt;&gt;s2;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>s1只读入4个字符，s2只读入3个字符</p><h3 id="ostrea类的成员函数" tabindex="-1"><a class="header-anchor" href="#ostrea类的成员函数"><span>ostrea类的成员函数</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>成员函数//相同作用的操纵流算子</span></span>
<span class="line"><span>precision(n)//setprecision(n)</span></span>
<span class="line"><span>width(w)//setw(w)</span></span>
<span class="line"><span>fill(c)//setfill(c)</span></span>
<span class="line"><span>setf(标志)//setiosflags(标志)</span></span>
<span class="line"><span>unsetf(标志)//resetiosflags(标志)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中用到的标志与其相同作用的流算子用到的标志相同</p><h5 id="put成员函数" tabindex="-1"><a class="header-anchor" href="#put成员函数"><span>put成员函数</span></a></h5><p>可以用来输出一个字符，其参数类型为int，的表示要输出字符的ascii码，返回值时cout的引用</p><h2 id="cerr标准错误输出流" tabindex="-1"><a class="header-anchor" href="#cerr标准错误输出流"><span>cerr标准错误输出流</span></a></h2><p>用于向屏幕输出出错信息，不能被重定向 常用于打印错误日志 cerr不使用缓冲区，直接向显示器输出信息</p><p>cerr对应c语言的stderr,和cout不同的是它每次输出都要刷新缓冲区无论是否使用endl,所以在打印关键信息的时候应该使用cerr,以免cout缓存输出的信息导致错误信息在不适合的地方输出</p><h2 id="clog" tabindex="-1"><a class="header-anchor" href="#clog"><span>clog</span></a></h2><p>输出到clog中的信息会先被存放到缓冲区，缓冲区满或者刷新时才输出到屏幕 常用于打印正常的日志</p>`,35)]))}const t=n(l,[["render",p]]),r=JSON.parse('{"path":"/cpp/cpp/8/","title":"8、输入输出流","lang":"zh-CN","frontmatter":{"title":"8、输入输出流","createTime":"2025/06/22 11:18:18","permalink":"/cpp/cpp/8/"},"readingTime":{"minutes":4.14,"words":1241},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/C++/C++/8、输入输出流.md","headers":[]}');export{t as comp,r as data};
